// ─── HOOKS ───────────────────────────────────────────────
function useTyping(words, speed=85, pause=2000) {
  const [disp,setDisp]=useState("");
  const [wi,setWi]=useState(0);
  const [ci,setCi]=useState(0);
  const [del,setDel]=useState(false);
  useEffect(()=>{
    const w=words[wi];
    const t=setTimeout(()=>{
      if(!del){setDisp(w.slice(0,ci+1));if(ci+1===w.length)setTimeout(()=>setDel(true),pause);else setCi(c=>c+1);}
      else{setDisp(w.slice(0,ci-1));if(ci-1===0){setDel(false);setWi(i=>(i+1)%words.length);setCi(0);}else setCi(c=>c-1);}
    },del?38:speed);
    return()=>clearTimeout(t);
  },[ci,del,wi,words,speed,pause]);
  return disp;
}

function useOnScreen(threshold = 0.1) {
  const ref = useRef(null);
  const [on, setOn] = useState(false);

  useEffect(() => {
    const ob = new IntersectionObserver(
      ([e]) => {
        if (e.isIntersecting) setOn(true);
      },
      { threshold }
    );

    if (ref.current) ob.observe(ref.current);

    return () => ob.disconnect();
  }, [threshold]);

  return [ref, on];
}
function FadeIn({children,delay=0,y=20}){
  const[ref,on]=useOnScreen();
  return(
    <div ref={ref} style={{opacity:on?1:0,transform:on?"none":`translateY(${y}px)`,transition:`opacity .65s ease ${delay}s,transform .65s ease ${delay}s`}}>
      {children}
    </div>
  );
}

